import{_ as e,c as o,o as d,ag as a}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"Sessions Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/sessions/SPEC.md","filePath":"packages/sessions/SPEC.md"}'),s={name:"packages/sessions/SPEC.md"};function n(r,t,c,i,l,h){return d(),o("div",null,t[0]||(t[0]=[a(`<h1 id="sessions-specification" tabindex="-1">Sessions Specification <a class="header-anchor" href="#sessions-specification" aria-label="Permalink to &quot;Sessions Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns session and chat management behavior for the Robota SDK. This package provides multi-session support with independent workspace isolation, chat instance lifecycle management, and agent template integration. It acts as the orchestration layer between consumer code and <code>@robota-sdk/agents</code>, giving each session its own set of chat instances backed by <code>Robota</code> agent instances.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own provider-specific transport behavior. All AI provider interactions are delegated to <code>@robota-sdk/agents</code> via <code>Robota</code> instances.</li><li>Does not own conversation history storage. Re-exports <code>ConversationHistory</code> and <code>ConversationSession</code> from <code>@robota-sdk/agents</code>.</li><li>Does not own agent configuration types (<code>IAgentConfig</code>, <code>TUniversalMessage</code>, <code>IRunOptions</code>, <code>IAgent</code>). These are re-exported from <code>@robota-sdk/agents</code> as the SSOT.</li><li>Does not own agent template definitions (<code>IAgentTemplate</code>, <code>AgentTemplates</code>). Adapts them through <code>TemplateManagerAdapter</code>.</li><li>Keeps session lifecycle, workspace isolation, and chat-level state management explicit within this package.</li><li>Persistence (<code>save</code>/<code>load</code> on <code>ChatInstance</code>) is declared but not yet implemented.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a three-layer structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>types/          -- Domain contracts (interfaces, enums, type aliases)</span></span>
<span class="line"><span>session/        -- SessionManager: top-level orchestrator for sessions and chats</span></span>
<span class="line"><span>chat/           -- ChatInstance: single chat wrapper around a Robota agent</span></span>
<span class="line"><span>adapters/       -- TemplateManagerAdapter: bridges agents template system to sessions interface</span></span></code></pre></div><p><strong>Design patterns used:</strong></p><ul><li><strong>Adapter pattern</strong> -- <code>TemplateManagerAdapter</code> adapts <code>AgentFactory</code> and <code>AgentTemplates</code> from <code>@robota-sdk/agents</code> to the local <code>ITemplateManager</code> interface.</li><li><strong>Facade pattern</strong> -- <code>SessionManager</code> provides a single entry point for creating sessions, creating chats, switching active chats, and querying session/chat state.</li><li><strong>Delegation</strong> -- <code>ChatInstance</code> delegates all AI execution (<code>run</code>, <code>getHistory</code>, <code>clearHistory</code>, <code>configure</code>) to the underlying <code>Robota</code> instance.</li><li><strong>Factory delegation</strong> -- <code>SessionManager</code> uses <code>AgentFactory</code> from <code>@robota-sdk/agents</code> to create <code>Robota</code> instances for each chat.</li></ul><p><strong>Dependency direction:</strong> <code>@robota-sdk/sessions</code> depends on <code>@robota-sdk/agents</code>. No reverse dependency exists.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>Types owned by this package (SSOT):</p><table tabindex="0"><thead><tr><th>Type</th><th>Kind</th><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>SessionState</code></td><td>Enum</td><td><code>types/core.ts</code></td><td>Session lifecycle states: <code>ACTIVE</code>, <code>PAUSED</code>, <code>TERMINATED</code></td></tr><tr><td><code>ISessionConfig</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Session configuration (name, maxChats, userId, workspaceId)</td></tr><tr><td><code>ISessionInfo</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Session runtime information and metadata</td></tr><tr><td><code>IChatInfo</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Summary information for a chat within a session</td></tr><tr><td><code>ISessionManagerConfig</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Manager-level configuration (maxSessions, maxChatsPerSession)</td></tr><tr><td><code>ICreateSessionOptions</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Options for creating a new session</td></tr><tr><td><code>ICreateChatOptions</code></td><td>Interface</td><td><code>types/core.ts</code></td><td>Options for creating a new chat (requires <code>agentConfig</code>)</td></tr><tr><td><code>TMessageContent</code></td><td>Type alias</td><td><code>types/chat.ts</code></td><td>Message content type (currently <code>string</code>)</td></tr><tr><td><code>IChatConfig</code></td><td>Interface</td><td><code>types/chat.ts</code></td><td>Chat-level configuration (robotaConfig, agentTemplate, description)</td></tr><tr><td><code>IChatMetadata</code></td><td>Interface</td><td><code>types/chat.ts</code></td><td>Chat metadata (id, timestamps, messageCount, isActive)</td></tr><tr><td><code>IChatStats</code></td><td>Interface</td><td><code>types/chat.ts</code></td><td>Chat statistics (messageCount, timestamps, optional token/timing)</td></tr><tr><td><code>ITemplateManager</code></td><td>Interface</td><td><code>types/chat.ts</code></td><td>Template manager contract (getTemplate, listTemplates, validateTemplate)</td></tr><tr><td><code>IChatInstance</code></td><td>Interface</td><td><code>types/chat.ts</code></td><td>Full chat instance contract (not exported publicly)</td></tr></tbody></table><p>Types re-exported from <code>@robota-sdk/agents</code> (not owned here):</p><table tabindex="0"><thead><tr><th>Type</th><th>Source</th></tr></thead><tbody><tr><td><code>IAgent</code></td><td><code>@robota-sdk/agents</code></td></tr><tr><td><code>IAgentConfig</code></td><td><code>@robota-sdk/agents</code></td></tr><tr><td><code>TUniversalMessage</code></td><td><code>@robota-sdk/agents</code></td></tr><tr><td><code>IRunOptions</code></td><td><code>@robota-sdk/agents</code></td></tr><tr><td><code>ConversationHistory</code></td><td><code>@robota-sdk/agents</code></td></tr><tr><td><code>ConversationSession</code></td><td><code>@robota-sdk/agents</code></td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>SessionManager</code></td><td>Class</td><td>Top-level manager: creates/deletes sessions, creates/deletes/switches chats, enforces limits</td></tr><tr><td><code>ChatInstance</code></td><td>Class</td><td>Wraps a <code>Robota</code> instance with session-scoped metadata, activation state, and template support</td></tr><tr><td><code>TemplateManagerAdapter</code></td><td>Class</td><td>Adapts <code>AgentFactory</code>/<code>AgentTemplates</code> from agents package to <code>ITemplateManager</code></td></tr><tr><td><code>ConversationHistory</code></td><td>Class (re-export)</td><td>Re-exported from <code>@robota-sdk/agents</code></td></tr><tr><td><code>ConversationSession</code></td><td>Class (re-export)</td><td>Re-exported from <code>@robota-sdk/agents</code></td></tr><tr><td><code>SessionState</code></td><td>Enum (via type export)</td><td>Exported through <code>types/core.ts</code> re-export</td></tr><tr><td><code>ITemplateManager</code></td><td>Interface</td><td>Template manager contract</td></tr><tr><td><code>IChatConfig</code></td><td>Interface</td><td>Chat configuration</td></tr><tr><td><code>IChatMetadata</code></td><td>Interface</td><td>Chat metadata</td></tr><tr><td><code>IChatStats</code></td><td>Interface</td><td>Chat statistics</td></tr><tr><td><code>TMessageContent</code></td><td>Type alias</td><td>Message content type</td></tr><tr><td><code>ISessionConfig</code></td><td>Interface</td><td>Session configuration</td></tr><tr><td><code>ISessionInfo</code></td><td>Interface</td><td>Session runtime info</td></tr><tr><td><code>IChatInfo</code></td><td>Interface</td><td>Chat summary info</td></tr><tr><td><code>ISessionManagerConfig</code></td><td>Interface</td><td>Manager configuration</td></tr><tr><td><code>ICreateSessionOptions</code></td><td>Interface</td><td>Session creation options</td></tr><tr><td><code>ICreateChatOptions</code></td><td>Interface</td><td>Chat creation options</td></tr><tr><td><code>IAgent</code></td><td>Interface (re-export)</td><td>From <code>@robota-sdk/agents</code></td></tr><tr><td><code>IAgentConfig</code></td><td>Interface (re-export)</td><td>From <code>@robota-sdk/agents</code></td></tr><tr><td><code>TUniversalMessage</code></td><td>Type alias (re-export)</td><td>From <code>@robota-sdk/agents</code></td></tr><tr><td><code>IRunOptions</code></td><td>Interface (re-export)</td><td>From <code>@robota-sdk/agents</code></td></tr></tbody></table><h3 id="key-sessionmanager-methods" tabindex="-1">Key SessionManager Methods <a class="header-anchor" href="#key-sessionmanager-methods" aria-label="Permalink to &quot;Key SessionManager Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>createSession</code></td><td><code>(options?: ICreateSessionOptions) =&gt; string</code></td><td>Creates a session, returns session ID. Throws on limit exceeded.</td></tr><tr><td><code>getSession</code></td><td><code>(sessionId: string) =&gt; ISessionInfo | undefined</code></td><td>Retrieves session info by ID.</td></tr><tr><td><code>listSessions</code></td><td><code>() =&gt; ISessionInfo[]</code></td><td>Lists all sessions.</td></tr><tr><td><code>deleteSession</code></td><td><code>(sessionId: string) =&gt; boolean</code></td><td>Deletes session and all its chats.</td></tr><tr><td><code>createChat</code></td><td><code>(sessionId: string, options: ICreateChatOptions) =&gt; Promise&lt;string&gt;</code></td><td>Creates a chat with a new <code>Robota</code> instance via <code>AgentFactory</code>.</td></tr><tr><td><code>getChat</code></td><td><code>(chatId: string) =&gt; ChatInstance | undefined</code></td><td>Retrieves a chat instance by ID.</td></tr><tr><td><code>getSessionChats</code></td><td><code>(sessionId: string) =&gt; IChatInfo[]</code></td><td>Lists all chats in a session.</td></tr><tr><td><code>switchChat</code></td><td><code>(sessionId: string, chatId: string) =&gt; boolean</code></td><td>Deactivates current active chat, activates the target chat.</td></tr><tr><td><code>deleteChat</code></td><td><code>(chatId: string) =&gt; boolean</code></td><td>Deletes a chat and updates session state.</td></tr></tbody></table><h3 id="key-chatinstance-methods" tabindex="-1">Key ChatInstance Methods <a class="header-anchor" href="#key-chatinstance-methods" aria-label="Permalink to &quot;Key ChatInstance Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>sendMessage</code></td><td><code>(content: TMessageContent) =&gt; Promise&lt;string&gt;</code></td><td>Sends message via <code>robota.run()</code>, updates metadata.</td></tr><tr><td><code>regenerateResponse</code></td><td><code>() =&gt; Promise&lt;string&gt;</code></td><td>Re-sends the last user message.</td></tr><tr><td><code>updateRobotaConfig</code></td><td><code>(config: IAgentConfig) =&gt; Promise&lt;void&gt;</code></td><td>Updates the underlying Robota configuration.</td></tr><tr><td><code>getRobotaConfig</code></td><td><code>() =&gt; IAgentConfig</code></td><td>Returns current agent config.</td></tr><tr><td><code>upgradeToTemplate</code></td><td><code>(templateName: string) =&gt; Promise&lt;void&gt;</code></td><td>Applies an agent template via <code>TemplateManagerAdapter</code>.</td></tr><tr><td><code>activate</code> / <code>deactivate</code></td><td><code>() =&gt; void</code></td><td>Toggles active state in metadata.</td></tr><tr><td><code>getHistory</code> / <code>clearHistory</code></td><td><code>() =&gt; TUniversalMessage[]</code> / <code>() =&gt; void</code></td><td>Delegates to <code>Robota</code> history management.</td></tr><tr><td><code>getStats</code></td><td><code>() =&gt; IChatStats</code></td><td>Returns chat statistics.</td></tr><tr><td><code>save</code> / <code>load</code></td><td><code>() =&gt; Promise&lt;void&gt;</code></td><td>Not yet implemented. Throws on call.</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ol><li><p><strong>ITemplateManager interface</strong> -- Consumers can provide a custom template manager implementation. The default <code>TemplateManagerAdapter</code> bridges to the agents package, but the <code>ITemplateManager</code> interface allows replacement.</p></li><li><p><strong>TemplateManagerAdapter.registerTemplate / unregisterTemplate</strong> -- Consumers can register custom <code>IAgentTemplate</code> instances at runtime to extend available templates.</p></li><li><p><strong>TemplateManagerAdapter.applyTemplate</strong> -- Consumers can apply a template with partial overrides to derive customized agent configurations.</p></li><li><p><strong>ICreateChatOptions.agentConfig</strong> -- Each chat creation accepts a full <code>IAgentConfig</code>, allowing consumers to configure provider, model, system prompt, and other agent parameters per chat.</p></li><li><p><strong>ISessionManagerConfig</strong> -- Consumers control session and chat limits through the manager configuration.</p></li></ol><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>This package does not define a custom error hierarchy. All errors are thrown as standard <code>Error</code> instances with descriptive messages. Error scenarios include:</p><table tabindex="0"><thead><tr><th>Error Condition</th><th>Thrown By</th><th>Message Pattern</th></tr></thead><tbody><tr><td>Session limit exceeded</td><td><code>SessionManager.createSession</code></td><td><code>&quot;Maximum sessions limit (N) reached...&quot;</code></td></tr><tr><td>Session not found</td><td><code>SessionManager.createChat</code></td><td><code>&quot;Session {id} not found&quot;</code></td></tr><tr><td>Chat limit exceeded</td><td><code>SessionManager.createChat</code></td><td><code>&quot;Maximum chats per session (N) reached&quot;</code></td></tr><tr><td>Message send failure</td><td><code>ChatInstance.sendMessage</code></td><td><code>&quot;Failed to send message: {cause}&quot;</code></td></tr><tr><td>No user message for regeneration</td><td><code>ChatInstance.regenerateResponse</code></td><td><code>&quot;No user message found to regenerate response for&quot;</code></td></tr><tr><td>Template not found</td><td><code>ChatInstance.upgradeToTemplate</code></td><td><code>&quot;Template &#39;{name}&#39; not found&quot;</code></td></tr><tr><td>Config update failure</td><td><code>ChatInstance.updateRobotaConfig</code></td><td><code>&quot;Failed to update robota config: {cause}&quot;</code></td></tr><tr><td>Persistence not implemented</td><td><code>ChatInstance.save</code> / <code>ChatInstance.load</code></td><td><code>&quot;Chat persistence not yet implemented&quot;</code> / <code>&quot;Chat loading not yet implemented&quot;</code></td></tr></tbody></table><p>Underlying AI provider errors propagate from <code>@robota-sdk/agents</code> and are wrapped in the message send/config update error paths.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IChatInstance</code></td><td><code>ChatInstance</code></td><td>production</td><td><code>src/chat/chat-instance.ts</code></td></tr><tr><td><code>ITemplateManager</code></td><td><code>TemplateManagerAdapter</code></td><td>production (adapter)</td><td><code>src/adapters/template-manager-adapter.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Classes are standalone.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>Robota</code> (agents)</td><td><code>ChatInstance</code></td><td><code>src/chat/chat-instance.ts</code></td></tr><tr><td><code>AgentFactory</code> (agents)</td><td><code>SessionManager</code></td><td><code>src/session/session-manager.ts</code></td></tr><tr><td><code>AgentTemplates</code> (agents)</td><td><code>TemplateManagerAdapter</code></td><td><code>src/adapters/template-manager-adapter.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-test-coverage" tabindex="-1">Current Test Coverage <a class="header-anchor" href="#current-test-coverage" aria-label="Permalink to &quot;Current Test Coverage&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Scope</th><th>Description</th></tr></thead><tbody><tr><td><code>src/session/session-manager.test.ts</code></td><td>Unit</td><td>Tests session CRUD, session limit enforcement, chat creation structure, workspace isolation</td></tr></tbody></table><h3 id="test-characteristics" tabindex="-1">Test Characteristics <a class="header-anchor" href="#test-characteristics" aria-label="Permalink to &quot;Test Characteristics&quot;">​</a></h3><ul><li>Uses <code>vitest</code> as the test runner.</li><li>Session management tests are fully synchronous and self-contained.</li><li>Chat creation tests use <code>try/catch</code> to handle expected failures when AI providers are not configured (no mock providers injected).</li><li>No integration tests with real AI providers.</li></ul><h3 id="gaps" tabindex="-1">Gaps <a class="header-anchor" href="#gaps" aria-label="Permalink to &quot;Gaps&quot;">​</a></h3><ul><li><strong>ChatInstance</strong> -- No dedicated unit tests. <code>sendMessage</code>, <code>regenerateResponse</code>, <code>updateRobotaConfig</code>, <code>upgradeToTemplate</code>, <code>activate</code>/<code>deactivate</code>, <code>getHistory</code>, <code>clearHistory</code>, <code>getStats</code>, and <code>updateConfig</code> are untested.</li><li><strong>TemplateManagerAdapter</strong> -- No unit tests for template lookup, listing, validation, registration, or <code>applyTemplate</code>.</li><li><strong>Chat switching</strong> -- <code>switchChat</code> is not covered in the existing test suite.</li><li><strong>Chat deletion</strong> -- <code>deleteChat</code> is not covered.</li><li><strong>Session deletion cascade</strong> -- Verifying that all child chats are cleaned up when a session is deleted.</li><li><strong>Type import correctness</strong> -- The test file imports <code>CreateSessionOptions</code> and <code>CreateChatOptions</code> (without <code>I</code> prefix), which may not match the actual exported type names (<code>ICreateSessionOptions</code>, <code>ICreateChatOptions</code>). This could indicate the test file is out of date or does not pass type checking.</li><li><strong>Persistence stubs</strong> -- <code>save</code>/<code>load</code> throw errors by design; no tests verify this behavior.</li></ul>`,42)]))}const m=e(s,[["render",n]]);export{g as __pageData,m as default};
